var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"아, 우리 마미 말이야?","JPN":"えっ、マミーのこと？","ENG":"Oh, you mean Mommy?","TWN":"啊，你說我們的媽咪嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"마미는 부지런하고, 운전도 잘하고, 샌드위치도 무지 맛있게 만들어줘~!","JPN":"マミーは頑張り屋さんで、運転が上手で、ものすごく\\n美味しいサンドイッチが作れるのにゃ～！","ENG":"She's diligent, a great driver, and makes one heck of a sandwich!","TWN":"媽咪不僅很勤奮，開車技術也很好，而且三明治也做得很好吃～！"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"하지만 문제는~ 내가 마냥 뒹굴기만 하면 되는 집고양이가 아니란 거양~","JPN":"ただし問題なのは～、ボミはずっとゴロゴロしてれば\\n満足な家ネコちゃんじゃないってことにゃ～。","ENG":"The problem is, I'm not just an ordinary house cat who can just nap all day!","TWN":"但問題是～我不是一隻只要在家打滾就行的家貓喵～"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"마미는 평소엔 상냥하지만, 우리가 일할 때만큼은 무쟈게 엄격해지거든.","JPN":"マミーは普段は優しいんだけど、ボミたちが\\nお仕事するときはものすごい厳しくなるのにゃ。","ENG":"Mommy's usually very sweet, but she's super strict when it comes to our work.","TWN":"媽咪平時雖然很和藹，但我們工作的時候就會變得很嚴格。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"지난 번엔 잠깐 졸았을 뿐인데! 내 소중한 베개를 보름 동안이나 압수 당했다구?","JPN":"この前、ちょっとうとうとしただけなのに！　ボミの大事な枕を半月も取り上げたのにゃ！","ENG":"The other day, I was dozing off for just one second! And she confiscated my pillow for two weeks!","TWN":"明明上次只是打了個瞌睡！就把我珍貴的枕頭沒收了半個月喔？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"이나 언니는...... 음......","JPN":"メグミさんは……うんと……","ENG":"Ina is... Well...","TWN":"理娜姐姐的話……嗯……"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"친절하고, 상냥하시고...... 또......","JPN":"親切で、優しくて……それから……","ENG":"She's kind, sweet... and...","TWN":"又親切，又溫柔……又……"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"아, 아무튼 엄청 좋은 사람이에요. 흠 잡을 데 없는......!","JPN":"と、とにかく、すごく良い方なんです。\\n文句のつけようがないような……！","ENG":"W-well, she's a super nice person, that's for sure. I've got nothing bad to say about her!","TWN":"總、總之是非常好的人，沒有缺點……！"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"웃는 게 부자연스럽다고 오프닝을 스무 번이나 찍은 건 심했다고 생각하지만......","JPN":"笑顔がぎこちないからって、オープニング映像を20回も\\n撮り直させたのはひどいと思いますけど……","ENG":"I mean, I think it was a tad much when she had us shoot 20 takes of the opening scene because our smiles were awkward...","TWN":"雖然因為我笑得不夠自然，拍了20次開場有點過分……"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"으...... 그래도 그 훈련 덕분에, 이젠 자연스럽게 웃을 수 있는 걸요!","JPN":"う……でも、あの訓練のおかげで、\\n今は自然に笑えるようになったんです！","ENG":"Eww... But thanks to that training, we can all smile very naturally!","TWN":"唔……但多虧那次訓練，現在我可以笑得很自然了！"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"에헤...... 헤헤......","JPN":"えへ……へへ……","ENG":"Heh... Heh heh...","TWN":"欸嘿……嘿嘿……"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"매니저님은 좋은 분이에요.","JPN":"マネージャーさんは良い人です。","ENG":"Our manager is a wonderful person.","TWN":"經紀人是個好人。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"현지에 적응하지 못하고 떠돌이생활을 하던 저에게 여러모로 많은 도움을 주셨어요.","JPN":"現地に適応できずに放浪していた私を、色々と助けてくださいました。","ENG":"She helped me in many ways when I was wandering about on the street in a foreign land.","TWN":"我曾經無法適應當地過著流浪生活，而她幫了我很多事情。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"지낼 곳을 마련해주고, 돈 버는 법도 가르쳐주고, 이름도 지어주셨죠.","JPN":"住むところを用意してくださいましたし、お金の稼ぎ方を\\n教えてくれて、名前も付けてくださいました。","ENG":"She gave me a place to sleep, taught me how to make money, and even gave me a name.","TWN":"她為我安排了住處，教我賺錢的方法，還給我取了名字。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"그리고...... 제 평생의 소원을 이루게 해주겠다고 약속도 하셨거든요.","JPN":"それから……私の一生の願いを\\n叶えさせてくれると、約束してくれました。","ENG":"And also... She promised she'd make my lifelong wish come true.","TWN":"然後……她還答應幫我實現畢生的願望。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......네? 초과근무? 노동자권리?","JPN":"……え？　超過勤務？　労働者の権利？","ENG":"Sorry? Overtime bonus? Workers' rights?","TWN":"……咦？加班？勞動者權利？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"저는 그런 어려운 말 몰라요.","JPN":"そんな難しい言葉は知りません。","ENG":"That all sounds too complicated for me.","TWN":"我不懂這些複雜的事情。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"아, 그 노랑 구두쇠 말이지?","JPN":"ああ、あの金髪の守銭奴のこと？","ENG":"Oh, you mean that stingy miser?","TWN":"啊，那個黃毛小氣鬼嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"딱히 고맙다곤 생각 안 해.","JPN":"別に有難いなんて思ってないわ。","ENG":"I don't really appreciate her that much.","TWN":"我沒有特別感謝她。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"돈은 최저시급 언저리인 주제에, 일은 쉴 틈 없이 부려먹기만 하고.","JPN":"もらえるお金は最低賃金ギリギリだし、そのくせ休む間もなくこき使ってくれるし。","ENG":"She pays us barely more than the minimum wage and keeps working our butts off.","TWN":"明明給的是最低工資，工作也沒有休息空檔，還到處使喚我。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"......그래! 이건 잠시 거쳐가는 계단 같은 거야.","JPN":"……そうよ！　これは成功へ向かうための通過儀礼みたいなものなの。","ENG":"Oh, I know! This is just a stepping stone.","TWN":"……不過！這只是暫時會經歷的階段。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"누구나 정상에 오르려면 아랫돌부터 차근히 밟아 올라가야 하는 법이잖아?","JPN":"トップに上り詰めるには、一番下から一段ずつ\\n積み重ねていくしかないでしょう？","ENG":"Everyone at the top had to have started somewhere, right?","TWN":"不論是誰，想站上頂點就必須從最下面開始，一步一步慢慢爬上去，對吧？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"내 수준에 어울리진 않지만, 인지도를 쌓을 동안 잠시 같이 있어주는 것뿐이라고.","JPN":"アタシのレベルには見合っていないグループだけど、もう少し認知度が\\n上がるまでしばらくの間一緒にいてあげてるの。","ENG":"I know this is beneath me, but I'm just keeping them company while I build up my fame.","TWN":"雖然這裡不符合我的程度，但我也只是在積累人氣，暫時和她們待在一起而已。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"응? 인터뷰...... 녹화?","JPN":"えっ？　インタビュー……収録ですって？","ENG":"Hm? This is an interview? And it's being recorded?","TWN":"嗯？採訪……錄影？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"그게 무슨 소리......","JPN":"それってどういう……","ENG":"What are you talking about—","TWN":"這是什麼意思……"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"......앗! 야! 잠깐!","JPN":"……あっ！　こら！　待ちなさいよ！","ENG":"Oh! Hey! Hang on!","TWN":"……啊！喂！等一下！"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};